import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface RetentionData {
  day: string;
  retention: number;
}

interface EngagementData {
  dauMauRatio: number;
  averageSessionDuration: string;
  retentionCurve: RetentionData[];
}

export default function Widget() {
  const engagementData = response.data as EngagementData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
              Engagement Insights
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              DAU/MAU Ratio: <Typography component="span" variant="body2" fontWeight={600} sx={{ color: '#03A9F4' }}>{(engagementData.dauMauRatio * 100).toFixed(1)}%</Typography>
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Avg. Session Duration: <Typography component="span" variant="body2" fontWeight={600} sx={{ color: '#03A9F4' }}>{engagementData.averageSessionDuration}</Typography>
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: engagementData.retentionCurve.map(d => d.retention),
                  color: '#03A9F4',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: engagementData.retentionCurve.map(d => d.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'retention', min: 0, max: 100 }]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="retention"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
